import "./FTANotepad.css";
import {useEffect, useState} from "react";
import { t } from 'ftc-common/i18n';
import {usePersistentWebsocket} from "ftc-common/utils";
import MatchView from "./MatchView";
import TeamView from "./TeamView";
import ListView from "./ListView";
import NoteDialog from "./NoteDialog";

function MatchToolbar({label, shortName, setCurrentMatch}) {
    return <div className={"matchBtn"}>
        <div>{label}</div>
        {shortName ? <button className={"btn btn-primary btn-sm"} onClick={() => setCurrentMatch(shortName)}>{shortName}</button> : null}
    </div>
}

export function matchSortShortname(a, b) {
    // Shortname is one of: G, Q#, M#, M#-#, F-#
    // A team will never appear in more than 1 match series per round, so dont worry about intra-round sorting for tiebreakers
    // TODO come back to this
    if (!a || !a[0]) return 1;
    if (!b || !b[0]) return -1;
    if (a[0] === b[0]) {
        const toNum = x => {
            const i = x.indexOf('-');
            if (i > 0) {
                return parseInt(x.substring(1, i) + (parseInt(x.substring(i)) / 100));
            }
            return parseInt(x.substring(1));
        }
        return toNum(a) - toNum(b);
    } else {
        const levelMap = {G: 0, Q: 1, M: 2, S: 3, F: 4, I: 5};
        const toLevel = (m) => levelMap[m[0]];
        return toLevel(a) - toLevel(b);
    }
}

export default function FTANotepad({eventCode, slackEnabled}) {
    const [view, setView] = useState('match');
    const [lastUpdate, setLastUpdate] = useState(null);
    const [matchList, setMatchList] = useState([]);
    const [teamList, setTeamList] = useState([]);
    const [currentTeam, setCurrentTeam] = useState(null);
    const [currentMatch, setCurrentMatch] = useState(null);
    const [activeMatch, setActiveMatch] = useState(null);
    const [loadedMatch, setLoadedMatch] = useState(null);
    const [issues, setIssues] = useState(new Map());
    const [showNote, setShowNote] = useState(false);
    const [activeNote, setActiveNote] = useState(null);
    const [pitAddresses, setPitAddresses] = useState({});
    const { isConnected, send } = usePersistentWebsocket(`/stream/fta/?code=${eventCode}`, (data) => {
        setLastUpdate(data);
    });

    useEffect(() => {
        let data = lastUpdate;
        if (!data) {
            return;
        }
        const updateIssueState = (issues) => {
            const initIssues = new Map();
            for (let team in issues) {
                initIssues.set(parseInt(team), issues[team]);
            }
            setIssues(initIssues);
        }
        if (data.type === "INIT") {
            setMatchList(data.matches);
            setTeamList(data.teams);
            // reverse to find last loaded that meets criteria
            const active = data.activeMatches.slice().reverse().find(m => ["AUTO", "TELEOP", "REVIEW", "SUBMITTED"].includes(m.state))?.shortName;
            const loaded = data.activeMatches.slice().reverse().find(m => ["UNPLAYED", "RANDOMIZED"].includes(m.state))?.shortName;
            const lastPlayed = data.matches.reduce((n, e) => e.start > n.start ? {start: e.start, match: e.shortName} : n, {start: 0, match: data.matches.length > 0 ? data.matches[0].shortName : null});
            setActiveMatch(active);
            setLoadedMatch(loaded === active ? null : loaded);
            setCurrentMatch(active ? active : (loaded ? loaded : lastPlayed.match));
            updateIssueState(data.issues);
            if (data.pits) {
                setPitAddresses(data.pits);
            }
        } else if (data.type === "PITS") {
            setPitAddresses(data.pits);
        } else if (data.type === "MATCH_LIST") {
            setMatchList(data.matches);
        } else if (data.type === "LOAD") {
            setLoadedMatch(data.match);
        } else if (data.type === "START") {
            setActiveMatch(data.match);
            if (loadedMatch === data.match) {
                setLoadedMatch(null);
            }
        } else if (data.type === "COMMIT") {
            const local = Array.from(matchList);
            const localMatch = local.find(x => x.shortName === data.match);
            if (localMatch) {
                localMatch.state = 'COMMITTED'; // make sure it shows up in "Completed" section for teams
                setMatchList(local);
            }
            if (data.match === activeMatch) {
                setActiveMatch(null);
            }
            if (data.match === loadedMatch) {
                setLoadedMatch(null);
            }
        } else if (data.type === "ABORT") {
            if (data.match === activeMatch) {
                setActiveMatch(null);
                setLoadedMatch(data.match);
            }
        } else if (data.type === "ISSUE") { // pull this into its own useEffect that listens for issueList changes?
            updateIssueState(data.issues);
        } else {
            console.log(data);
        }
    }, [lastUpdate, activeMatch, loadedMatch, matchList]);

    const openTeam = (number) => {
        setCurrentTeam(number);
        setView('team');
    }
    const openMatch = (shortName) => {
        setCurrentMatch(shortName);
        setView('match');
    }
    const saveNote = (note) => {
        if (!note.type) {
            note.type = 'OTHER';
        }
        send(JSON.stringify({type: "ISSUE", issue: note}))
    }
    const createNote = (match, team) => {
        setActiveNote({match: match, team: team, sendToSlack: true});
        setShowNote(true);
    }
    const openNote = (note) => {
        setActiveNote(note);
        setShowNote(true);
    }

    let content = null;
    if (view === 'match') {
        content = <MatchView match={currentMatch} matchList={matchList} issues={issues} setCurrentMatch={setCurrentMatch}
                              openTeam={openTeam} openNote={createNote}/>;
    } else if (view === 'team' ) {
        content = <TeamView team={currentTeam} teamName={teamList.find(x => x.data.number === currentTeam)?.data.name}
                             displayNumber={teamList.find(x => x.data.number === currentTeam)?.data.displayNumber}
                             issues={issues.get(currentTeam)} currentMatch={currentMatch} matchList={matchList} openMatch={openMatch}
                             saveNoteCallback={saveNote} openNote={openNote} pitAddress={pitAddresses?.[currentTeam]}/>;
    } else if (view === 'list') {
        content = <ListView teams={teamList} issues={issues} saveNoteCallback={saveNote} openNote={openNote} pitAddresses={pitAddresses}/>;
    }
    const leftToolbar = view === 'match' ? [
            <MatchToolbar key='loaded' label={t`Loaded Match`} shortName={loadedMatch} setCurrentMatch={setCurrentMatch} />,
            <MatchToolbar key='active' label={t`Active Match`} shortName={activeMatch} setCurrentMatch={setCurrentMatch} />
        ] : <button className={"btn btn-secondary toolbarBtn"} onClick={() => setView('match')}>{t`Match View`}</button>;
    const teams = teamList.map(t => <button className={"dropdown-item"} key={t.data.number} onClick={() => openTeam(t.data.number)}>{t.data.displayNumber}</button>)
    return  <div className={"justify-content-center"}>
        { isConnected ? null : <div className={"alert alert-danger text-center h6"}>{t`DISCONNECTED`}</div> }
        <NoteDialog show={showNote} setShow={setShowNote} note={activeNote} setNote={setActiveNote} saveNote={saveNote} slackEnabled={slackEnabled}/>
        <div className={"ftaToolbar"}>
            {leftToolbar}
            <div className={"ftaToolbarRight"} style={{marginLeft: "auto"}}>
                <button className={"btn btn-secondary toolbarBtn dropdown-toggle"} data-toggle={"dropdown"} aria-haspopup={"true"} aria-expanded={"false"}>{t`Teams`}</button>
                <div className={"dropdown-menu"} aria-labelledby={"teamsBtn"}>
                    {teams}
                </div>
                <button className={"btn btn-secondary toolbarBtn"} onClick={() => setView('list')}><i className={"fa fa-list"}/></button>
            </div>
        </div>
        {content}
    </div>
}