import "./TeamView.css";
import { t } from 'ftc-common/i18n';
import IssueItem from "./IssueItem";
import {matchSortShortname} from "./FTANotepad";

export default function TeamView({team, displayNumber, teamName, issues, matchList, currentMatch, openMatch, saveNoteCallback, openNote, pitAddress}) {
    const hasTeam = (m, t) => {
        for (let a of ['red', 'blue']) {
            for (let r of [1,2,3]) {
                if (m[a]["team" + r]?.data.number === t) {
                    return true;
                }
            }
        }
        return false;
    }
    const toMatchItem = (m) => <div className={`teamMatch teamMatchListItem ${currentMatch === m.shortName ? "current" : ""}`} key={m.shortName} onClick={() => openMatch(m.shortName)}>{m.shortName}</div>
    const hasMe = matchList.filter(x => hasTeam(x, team));
    const canAddIssue = hasMe.map(x => x.shortName === currentMatch).includes(true);
    const completed = hasMe.filter(x => x.state === 'COMMITTED').map(toMatchItem);
    const future = hasMe.filter(x => x.state !== 'COMMITTED').map(toMatchItem);
    const sorted = issues?.sort((a,b) => matchSortShortname(a.match, b.match));
    const active = sorted?.filter(x => !x.resolved).map(x => <IssueItem issue={x} saveNoteCallback={saveNoteCallback} openNote={openNote} key={x.id}/>);
    const resolved = sorted?.filter(x => x.resolved).map(x => <IssueItem issue={x} saveNoteCallback={saveNoteCallback} openNote={openNote} key={x.id}/>);
    const pit = pitAddress ? ` (${pitAddress})` : '';
    return <div className={"teamView"}><br/>
        <div className={"teamHeader"}>
            <div className={"teamNumber h4"}>{`Team #${displayNumber}${pit}`}</div>
            <div className={"teamName"}>{teamName}</div>
        </div>
        <div className={"teamBody"}>
            <div style={{width: "75%", borderRight: "1px solid black"}}>
                <div style={{margin: ".5em", minHeight: "300px"}}>
                    <div className={"teamIssueListHeader teamIssueListItem active"}>{t`ACTIVE:`}</div>
                    {active}
                    <div className={"teamIssueListHeader teamIssueListItem resolved"}>{t`RESOLVED:`}</div>
                    {resolved}
                </div>
                {canAddIssue ? <div style={{textAlign: "center", margin: ".3em"}}><button style={{width: "50%"}} className={"btn btn-sm btn-dark"} onClick={() => openNote({match: currentMatch, team: team, sendToSlack: true})}>{t`Add Match Issue`}</button></div> : null}
                <div style={{textAlign: "center", margin: ".3em"}}><button style={{width: "50%"}} className={"btn btn-sm btn-dark"} onClick={() => openNote({match: 'G', team: team, sendToSlack: true})}>{t`Add General Issue`}</button></div>
            </div>
            <div style={{width: "25%", textAlign: "center"}}>
                <div style={{fontWeight: 'bold'}}>Matches</div>
                <div className={"teamMatchListHeader teamMatchListItem"}>{t`COMPLETE:`}</div>
                {completed}
                <div className={"teamMatchListHeader teamMatchListItem"}>{t`FUTURE:`}</div>
                {future}
            </div>
        </div>
    </div>
}