import './ListView.css';
import { t } from 'ftc-common/i18n';
import IssueItem from "./IssueItem";
import {useState} from "react";
import {matchSortShortname} from "./FTANotepad";

function renderByTeam(issues, teams, filter, saveNoteCallback, openNote, pitAddresses) {
    const content = [];
    const keys = Array.from(issues.keys()).sort((a,b) => a - b);
    for (let team of keys) {
        let teamIssues = issues.get(team).filter(x => filter !== 'active' || !x.resolved);
        if (teamIssues.length) {
            content.push(<div className={"teamIssueListHeader teamIssueListItem"} key={team}>{teams.find(x => x.data.number === team)?.data.displayNumber} {pitAddresses?.[team] ? `(${pitAddresses?.[team]}) ` : null}- {teams.find(x => x.data.number === team)?.data.name}</div>);
            for (let issue of teamIssues.sort((a,b) => matchSortShortname(a.match, b.match))) {
                content.push(<IssueItem issue={issue} saveNoteCallback={saveNoteCallback} openNote={openNote} key={`${issue.team}_${issue.id}`}/>)
            }
        }
    }
    return content;
}

function renderByMatch(issues, teams, filter, saveNoteCallback, openNote, pitAddresses) {
    const content = [];
    const byMatch = new Map();
    const keys = Array.from(issues.keys()).sort((a,b) => a - b);
    for (let team of keys) {
        for (let issue of issues.get(team).filter(x => filter !== 'active' || !x.resolved)) {
            const matchIssues = byMatch.has(issue.match) ? byMatch.get(issue.match) : [];
            matchIssues.push(issue);
            byMatch.set(issue.match, matchIssues);
        }
    }
    for (let match of Array.from(byMatch.keys()).sort(matchSortShortname)) {
        content.push(<div className={"teamIssueListHeader teamIssueListItem"} key={match}>{match}</div>);
        for (let issue of Array.from(byMatch.get(match)).sort((a,b) => a.team - b.team)) {
            content.push(<IssueItem teams={teams} issue={issue} saveNoteCallback={saveNoteCallback} label={"team"} openNote={openNote} key={`${issue.team}_${issue.id}`} address={pitAddresses?.[issue.team]}/>)
        }
    }
    return content;
}
export default function ListView({teams, issues, saveNoteCallback, openNote, pitAddresses}) {
    const [group, setGroup] = useState('team');
    const [filter, setFilter] = useState('active');

    const content = group === 'team' ? renderByTeam(issues, teams, filter, saveNoteCallback, openNote, pitAddresses) : renderByMatch(issues, teams, filter, saveNoteCallback, openNote, pitAddresses);

    return <div><br/>
        <div className={"listHeader h6"}>
            <div>
                {t`Group: `}
                <button className={`btn btn-sm ${group === 'team' ? "btn-secondary" : "btn-outline-secondary"}`} onClick={() => setGroup('team')}>{t`Team`}</button>
                <button className={`btn btn-sm ${group === 'match' ? "btn-secondary" : "btn-outline-secondary"}`} onClick={() => setGroup('match')} style={{marginLeft: "1ch"}}>{t`Match`}</button>
            </div>
            <div style={{marginLeft: 'auto'}}>
                {t`Show: `}
                <button className={`btn btn-sm ${filter === 'all' ? "btn-secondary" : "btn-outline-secondary"}`} onClick={() => setFilter('all')}>{t`All`}</button>
                <button className={`btn btn-sm ${filter === 'active' ? "btn-secondary" : "btn-outline-secondary"}`} onClick={() => setFilter('active')} style={{marginLeft: "1ch"}}>{t`Active`}</button>
            </div>
        </div>
        <div className={"issueList"}>
            <div className={"teamIssuesContainer"}>
                {content}
            </div>
        </div>
    </div>
}