import "./MatchView.css";

function TeamSlot({match, team, alliance, issues, hidden, openTeam, openNote}) {
    if(!team) {
        team = {};
    }
    let teamIssues = issues.get(team.number) || [];
    let active = teamIssues.reduce((n, e) => !e.resolved ? n + 1 : n, 0);
    let resolved = teamIssues.reduce((n, e) => e.resolved ? n + 1 : n, 0);
    return hidden ? null : <div className={`matchTeam ${alliance}`}>
        <div className={"teamNumber"} onClick={() => openTeam(team.number)}>{team.displayNumber}</div>
        {team.number ? <div className={"issueGroup"}>
            <div className={"active issueCount"}>A: {active}</div>
            <div className={"resolved issueCount"}>R: {resolved}</div>
            <button className={"newIssue"} onClick={() => openNote(match, team.number)}><i className={"fa fa-plus-circle fa-4"}/></button>
        </div> : null}
    </div>
}

export default function MatchView({match, matchList, issues, setCurrentMatch, openTeam, saveNoteCallback, openNote}) {
    let matchIndex = match ? matchList.findIndex(m => m.shortName === match) : -1;
    let matchObj = matchIndex >= 0 ? matchList[matchIndex] : null;
    let r3 = matchObj?.red.team3 || matchObj?.blue.team3;
    let teams = [1, 2, 3].map(r => ['red', 'blue'].map(a => <TeamSlot match={match} team={matchObj?.[a]["team" + r]?.data} alliance={a} key={`${a}_${r}`} issues={issues} hidden={r === 3 && !r3} openTeam={openTeam} openNote={openNote}/>));
    let matches = matchList ? matchList.map(m => <button className={"dropdown-item"} key={m.shortName} onClick={() => setCurrentMatch(m.shortName)}>{m.shortName}</button>) : [];

    return <div className={"matchView"}>
        <br/>
        <div className={"matchHeader"}>
            <button className={"matchLeft btn btn-secondary"} disabled={matchIndex <= 0} onClick={() => setCurrentMatch(matchList[matchIndex - 1].shortName)}><i className={"fa fa-arrow-left"}/></button>
            <span className={"matchName h4"}>{t`Match ${match}`}</span>
            <button className={"btn btn-secondary btn-sm dropdown-toggle"} data-toggle="dropdown" aria-haspopup="true" aria-expanded="false"/>
            <div className="dropdown-menu" aria-labelledby="matchSearch">
                {matches}
            </div>
            <button className={"btn btn-secondary"} disabled={matchIndex < 0 || matchIndex >= matchList.length - 1} onClick={() => setCurrentMatch(matchList[matchIndex + 1].shortName)}><i className={"fa fa-arrow-right"}/></button>
        </div>
        <div className={"matchInfo"}>
            Field: {matchObj?.field}
        </div>
        <div className={"matchTeams"}>
            {teams}
        </div>
    </div>
}