import './IssueItem.css';

export default function IssueItem({issue, saveNoteCallback, label, openNote, teams, address}) {
    const TYPE_MAP = {
        DS_PHONE: t`DS Issue (Phone)`,
        DS_HUB: t`DS Issue (Hub)`,
        RC_PHONE: t`RC Issue (Phone)`,
        RC_HUB: t`RC Issue (Hub)`,
        NO_ROBOT: t`No Robot`,
        CONFIG: t`Configuration Issue`,
        POWER: t`Robot Power Issue`,
        CONNECTION: t`Connection Issue`,
        ELECTRICAL: t`Electrical Issue`,
        OTHER_ROBOT: t`Other Robot Issue`,
        INSPECTION: t`Inspection Issue`,
        OTHER: t`Other Issue`
    }
    const onclick = (e) => {
        e.stopPropagation();
        issue.resolved = !issue.resolved;
        saveNoteCallback(issue);
    }
    return <div className={`teamIssue teamIssueListItem ${issue.resolved ? "resolved" : "active"}`} onClick={() => openNote(issue)}>
        <div className={"teamIssueItemLeft"}>
            <div className={"teamIssueItemTop"}>
                <span className={`teamIssueMatch ${label === 'team' && address ? "address" : null}`}>{label === 'team' ? (teams.find(x => x.data.number === issue.team)?.data.displayNumber + (address ? ` (${address})` : '')) : issue.match}</span>
                <div className={"teamIssueType"}>{TYPE_MAP[issue.type]}</div>
            </div>
            <div className={"teamIssueSummary"}>{issue.summary}</div>
        </div>
        <button onClick={onclick}><i className={`fa-2x ${issue.resolved ? "fa fa-check-circle" : "far fa-circle"}`}/></button>
    </div>
}