import {Button, Modal, Form} from "react-bootstrap";
import {useId} from "react";
import {confirmDialog} from "first-common/dialogs";

export default function NoteDialog({show, setShow, note, setNote, saveNote, slackEnabled}) {
    const sendToSlackId = useId();
    const resolvedId = useId();
    if (!note) {
        return null;
    }
    function updateNote(changes) {
        setNote(Object.assign({}, note, changes));
    }

    // check send to slack if it has already been sent to slack or if selected now (unless marking resolved)
    let sendToSlackChecked = note.sendToSlack || note.slackId;
    if (sendToSlackChecked && note.resolved && !note.slackId) {
        // Don't check if resolved and not already sent
        sendToSlackChecked = false;
    }

    return <Modal show={show} onHide={() => setShow(false)} size="lg" className="noteModal">
        <Modal.Header closeButton>
            <Modal.Title>{t`Team Issue`}</Modal.Title>
        </Modal.Header>
        <Modal.Body>
            {note.match !== 'G' ? <><Form.Label>{t`Match: ${note.match}`}</Form.Label><br/></> : null}
            <Form.Label>{t`Team: ${note.team}`}</Form.Label><br/>
            <label htmlFor={"noteTypeInput"}>{t`Type:`}</label>
            <select id={"noteTypeInput"} style={{marginLeft: "10px"}} value={note.type || 'OTHER'} onChange={(e) => updateNote({type: e.target.value})}>
                <option value="DS_PHONE">{t`DS Issue (Phone)`}</option>
                <option value="DS_HUB">{t`DS Issue (Hub)`}</option>
                <option value="RC_PHONE">{t`RC Issue (Phone)`}</option>
                <option value="RC_HUB">{t`RC Issue (Hub)`}</option>
                <option value="NO_ROBOT">{t`No Robot`}</option>
                <option value="CONFIG">{t`Configuration Issue`}</option>
                <option value="POWER">{t`Robot Power Issue`}</option>
                <option value="CONNECTION">{t`Connection Issue`}</option>
                <option value="ELECTRICAL">{t`Electrical Issue`}</option>
                <option value="OTHER_ROBOT">{t`Other Robot Issue`}</option>
                <option value="INSPECTION">{t`Inspection Issue`}</option>
                <option value="OTHER">{t`Other Issue`}</option>
            </select><br/>
            <Form.Label className={"drop"}>{t`Summary:`}</Form.Label>
            <Form.Control type={"text"} value={note.summary || ''} onChange={(e) => updateNote({summary: e.target.value})}/>
            <Form.Label className={"drop"}>{t`Details:`}</Form.Label>
            <Form.Control as={"textarea"} value={note.details || ''} rows={4} style={{width: "100%"}} onChange={(e) => updateNote({details: e.target.value})}/><br/>

            <Form.Check label={"Resolved?"} id={resolvedId} checked={note.resolved} onChange={(e) => updateNote({resolved: e.target.checked})}/>
            {slackEnabled ? <Form.Check label={"Send to slack?"} id={sendToSlackId} checked={sendToSlackChecked} onChange={(e) => updateNote({sendToSlack: e.target.checked})} disabled={note.slackId || note.resolved}/> : null}

        </Modal.Body>
        <Modal.Footer>
            <Button variant={"danger"} onClick={() => {
                setShow(false);
                confirmDialog({
                    label: t`Confirm Note Delete`,
                    text: t`This will permanently delete the note. Continue?`,
                    onConfirm: () => {
                        saveNote(Object.assign({}, note, {id: -note.id}));
                        setShow(false);
                    }
                })
            }} style={{marginRight: "auto"}} hidden={!note.id}>{t`Delete`}</Button>
            <Button variant={"secondary"} onClick={() => setShow(false)}>{t`Cancel`}</Button>
            <Button variant={"primary"} onClick={() => {
                saveNote(note);
                setShow(false);
            }}>{t`Save`}</Button>
        </Modal.Footer>
    </Modal>
}